# Spaceship Simulator
import math

class Ship:
    def __init__(self, name):
        self.name = name
        self.x = 0
        self.y = 0
        self.fuel = 100
        self.speed = 0

    def thrust(self, power):
        self.speed += power
        self.fuel -= power * 0.1

    def move(self):
        self.x += self.speed

    def brake(self):
        self.speed = max(0, self.speed - 5)

class Fleet:
    def __init__(self):
        self.ships = []

    def add(self, ship):
        self.ships.append(ship)

    def move_all(self):
        for ship in self.ships:
            ship.move()

    def status(self):
        for s in self.ships:
            print(f"{s.name}: ({s.x},{s.y})")
